import { useState } from 'react'
import { useAuth } from '../auth/AuthContext.jsx'

const logoIcetel     = "data:image/png;base64,"
const logoNextstream = "data:image/svg+xml;base64,"

export default function Login() {
  const { signIn } = useAuth()
  const [email,    setEmail]    = useState('')
  const [password, setPassword] = useState('')
  const [err,      setErr]      = useState('')
  const [busy,     setBusy]     = useState(false)

  const submit = async (e) => {
    e.preventDefault()
    setErr(''); setBusy(true)
    const error = await signIn(email.trim(), password)
    setBusy(false)
    if (error) {
      setErr(
        error.message === 'Invalid login credentials'
          ? 'Correo o contraseña incorrectos.'
          : error.message
      )
    }
  }

  return (
    <div className="login-wrap">
      <form className="login-card" onSubmit={submit}>
        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 24, marginBottom: 8 }}>
          <img src={logoIcetel} alt="Icetel" style={{ height: 48, objectFit: 'contain' }} />
          <span style={{ color: '#cbd5e1', fontSize: 20, fontWeight: 300 }}>×</span>
          <img src={logoNextstream} alt="Nextstream" style={{ height: 48, objectFit: 'contain' }} />
        </div>

        <div className="brand" style={{ marginTop: 8 }}>
          <div className="name">CMDB <span>Icetel</span></div>
        </div>

        <p className="lead">
          Base de activos de infraestructura de misión crítica.<br/>
          Ingresa con tu cuenta corporativa.
        </p>

        {err && <div className="login-error">{err}</div>}

        <div className="field">
          <label htmlFor="email">Correo</label>
          <input
            id="email" type="email" autoComplete="username" required
            value={email} onChange={(e) => setEmail(e.target.value)}
            placeholder="usuario@icetel.cl"
          />
        </div>
        <div className="field">
          <label htmlFor="pwd">Contraseña</label>
          <input
            id="pwd" type="password" autoComplete="current-password" required
            value={password} onChange={(e) => setPassword(e.target.value)}
            placeholder="••••••••"
          />
        </div>

        <button className="btn btn-primary" disabled={busy}>
          {busy ? 'Ingresando…' : 'Ingresar'}
        </button>

        <div className="login-foot">
          Acceso restringido · Icetel / Nextstream · Datacenter
        </div>
      </form>
    </div>
  )
}
